import { useState } from 'react';
import { Link } from 'react-router-dom';
import { usePortfolio } from '../contexts/PortfolioContext';
import PortfolioSummary from '../components/PortfolioSummary';
import { formatPKR } from '../utils/finance';
import { RiskBadge, CategoryBadge } from '../components/Badges';
import './Portfolio.css';

export default function Portfolio() {
  const { items, stats, removeFromPortfolio, updateAllocation } = usePortfolio();

  if (items.length === 0) {
    return (
      <div className="page page-enter">
        <div className="container">
          <div className="port-header">
            <h1 className="section-title">My <span>Portfolio</span></h1>
          </div>
          <div className="empty-state" style={{ paddingTop: 100 }}>
            <div style={{ fontSize: 48, marginBottom: 16 }}>📂</div>
            <h3>Your portfolio is empty</h3>
            <p style={{ marginTop: 8, marginBottom: 24 }}>Browse products and add them to track your investments</p>
            <Link to="/products" className="btn btn-primary">Browse Products →</Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="page page-enter">
      <div className="container">
        <div className="port-header">
          <div>
            <h1 className="section-title">My <span>Portfolio</span></h1>
            <p className="section-subtitle">{items.length} product{items.length > 1 ? 's' : ''} · Total: {formatPKR(stats.totalInvested)}</p>
          </div>
          <Link to="/products" className="btn btn-outline btn-sm">+ Add Products</Link>
        </div>

        <div className="port-layout">
          {/* Items */}
          <div className="port-items">
            {items.map(item => (
              <PortfolioItem
                key={item.product.id}
                item={item}
                totalInvested={stats.totalInvested}
                onRemove={() => removeFromPortfolio(item.product.id)}
                onUpdateAmount={amt => updateAllocation(item.product.id, amt)}
              />
            ))}
          </div>

          {/* Summary */}
          <div className="port-summary-wrap">
            <PortfolioSummary stats={stats} />

            <div className="port-annual-card card">
              <p className="port-annual-label">Est. Annual Earnings</p>
              <p className="port-annual-val">
                {formatPKR(stats.totalInvested * stats.weightedReturn / 100)}
              </p>
              <p className="port-annual-sub">at {stats.weightedReturn}% weighted return</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function PortfolioItem({ item, totalInvested, onRemove, onUpdateAmount }) {
  const { product, amount } = item;
  const [editing, setEditing] = useState(false);
  const [tempAmount, setTemp] = useState(String(amount));
  const pct = totalInvested > 0 ? ((amount / totalInvested) * 100).toFixed(1) : '0';
  const annualReturn = (amount * product.expectedReturn / 100);

  function saveAmount() {
    const val = Number(tempAmount);
    if (val >= product.minInvestment) { onUpdateAmount(val); }
    setEditing(false);
  }

  return (
    <div className="pi-card card">
      <div className="pi-main">
        <div className="pi-info">
          <div className="pi-badges">
            <CategoryBadge category={product.category} />
            <RiskBadge riskLevel={product.riskLevel} />
          </div>
          <h4 className="pi-name">{product.name}</h4>
          <p className="pi-return">+{product.expectedReturn}% p.a. · Est. +{formatPKR(annualReturn)}/year</p>
        </div>

        <div className="pi-amount-wrap">
          {editing ? (
            <div className="pi-edit-row">
              <input
                type="number"
                className="form-input"
                value={tempAmount}
                min={product.minInvestment}
                onChange={e => setTemp(e.target.value)}
                style={{ width: 120 }}
              />
              <button className="btn btn-primary btn-sm" onClick={saveAmount}>Save</button>
              <button className="btn btn-outline btn-sm" onClick={() => { setEditing(false); setTemp(String(amount)); }}>✕</button>
            </div>
          ) : (
            <div className="pi-amount-display">
              <span className="pi-amount">{formatPKR(amount)}</span>
              <span className="pi-pct">{pct}% of portfolio</span>
              <button className="pi-edit-btn" onClick={() => setEditing(true)}>Edit</button>
            </div>
          )}
        </div>
      </div>

      <button className="pi-remove" onClick={onRemove} title="Remove from portfolio">✕</button>
    </div>
  );
}
